**LocalStorageService.cs:**
```csharp
using Microsoft.JSInterop;
using SiteInspector.Client.Models;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("indexedDbInterop.initialize");
    }

    // Sites
    public async Task SaveSiteAsync(Site site)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.put", "sites", site);
    }

    public async Task<List<Site>> GetAllSitesAsync()
    {
        return await _js.InvokeAsync<List<Site>>("indexedDbInterop.getAll", "sites") ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        return await _js.InvokeAsync<Site?>("indexedDbInterop.get", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.put", "inspections", inspection);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        return await _js.InvokeAsync<List<Inspection>>("indexedDbInterop.getAllByIndex", "inspections", "siteId", siteId) ?? new();
    }

    public async Task<List<Inspection>> GetPendingInspectionsAsync()
    {
        return await _js.InvokeAsync<List<Inspection>>("indexedDbInterop.getAllByIndex", "inspections", "syncStatus", (int)SyncStatus.Pending) ?? new();
    }

    public async Task<int> GetPendingSyncCountAsync()
    {
        return await _js.InvokeAsync<int>("indexedDbInterop.countByIndex", "inspections", "syncStatus", (int)SyncStatus.Pending);
    }

    // Checklist Items
    public async Task SaveChecklistItemAsync(ChecklistItem item)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.put", "checklistItems", item);
    }

    public async Task<List<ChecklistItem>> GetChecklistItemsByInspectionAsync(string inspectionId)
    {
        return await _js.InvokeAsync<List<ChecklistItem>>("indexedDbInterop.getAllByIndex", "checklistItems", "inspectionId", inspectionId) ?? new();
    }

    // Photos
    public async Task SavePhotoAsync(Photo photo)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.put", "photos", photo);
    }

    public async Task<List<Photo>> GetPhotosByInspectionAsync(string inspectionId)
    {
        return await _js.InvokeAsync<List<Photo>>("indexedDbInterop.getAllByIndex", "photos", "inspectionId", inspectionId) ?? new();
    }

    public async Task DeletePhotoAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.delete", "photos", id);
    }
}
```

**ConnectivityService.cs:**
```csharp
using Microsoft.JSInterop;

namespace SiteInspector.Client.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
    private bool _isOnline = true;

    public event Action<bool>? OnConnectivityChanged;
    public bool IsOnline => _isOnline;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        _isOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public void OnStatusChanged(bool isOnline)
    {
        _isOnline = isOnline;
        OnConnectivityChanged?.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}
```

**SyncService.cs:**
```csharp
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncBatch
{
    public List<Inspection> Inspections { get; set; } = new();
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<Photo> Photos { get; set; } = new();
}

public class SyncService
{
    private readonly HttpClient _http;
    private readonly LocalStorageService _storage;
    private readonly ConnectivityService _connectivity;

    public event Action? OnSyncStatusChanged;

    public SyncService(HttpClient http, LocalStorageService storage, ConnectivityService connectivity)
    {
        _http = http;
        _storage = storage;
        _connectivity = connectivity;
    }

    public async Task<bool> TrySyncAsync()
    {
        if (!_connectivity.IsOnline) return false;

        try
        {
            var pendingInspections = await _storage.GetPendingInspectionsAsync();
            if (pendingInspections.Count == 0) return true;

            var batch = new SyncBatch { Inspections = pendingInspections };

            foreach (var inspection in pendingInspections)
            {
                var items = await _storage.GetChecklistItemsByInspectionAsync(inspection.Id);
                batch.ChecklistItems.AddRange(items);

                var photos = await _storage.GetPhotosByInspectionAsync(inspection.Id);
                batch.Photos.AddRange(photos);
            }

            var response = await _http.PostAsJsonAsync("/api/inspections/sync", batch);

            if (response.IsSuccessStatusCode)
            {
                foreach (var inspection in pendingInspections)
                {
                    inspection.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveInspectionAsync(inspection);
                }
                OnSyncStatusChanged?.Invoke();
                return true;
            }
            else
            {
                foreach (var inspection in pendingInspections)
                {
                    inspection.SyncStatus = SyncStatus.Failed;
                    await _storage.SaveInspectionAsync(inspection);
                }
                OnSyncStatusChanged?.Invoke();
                return false;
            }
        }
        catch
        {
            OnSyncStatusChanged?.Invoke();
            return false;
        }
    }
}
