                                    @onclick="() => SetStatus(item, ChecklistStatus.Pass)">✓ Pass</button>
                            <button class="btn-status @(item.Status == ChecklistStatus.Fail ? "active-fail" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.Fail)">✗ Fail</button>
                            <button class="btn-status @(item.Status == ChecklistStatus.NA ? "active-na" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.NA)">N/A</button>
                        </div>
                        <input type="text" @bind="item.Notes" placeholder="Notes (optional)" class="form-input form-input-sm" />
                        <PhotoCapture InspectionId="@_inspection.Id" ChecklistItemId="@item.Id" />
                    </div>
                }
            </div>
        }

        <div class="form-group">
            <label>General Notes</label>
            <textarea @bind="_inspection.Notes" placeholder="Additional notes..." class="form-input form-textarea"></textarea>
        </div>

        <PhotoCapture InspectionId="@_inspection.Id" ChecklistItemId="@null" />

        <button class="btn btn-primary btn-full" @onclick="Complete">Complete Inspection</button>
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Inspection _inspection = new();
    private List<ChecklistItem> _checklistItems = new();
    private List<string> _categories = new();
    private bool _initialized;

    private static readonly Dictionary<string, string[]> DefaultChecklist = new()
    {
        ["Personal Protective Equipment"] = new[] { "Hard hats", "Safety vests", "Steel-toe boots", "Eye protection", "Hearing protection" },
        ["Fall Protection"] = new[] { "Guardrails", "Safety nets", "Harness systems", "Floor hole covers", "Ladder condition" },
        ["Electrical Safety"] = new[] { "GFCI protection", "Cord condition", "Panel access", "Lockout/tagout", "Temporary wiring" },
        ["Housekeeping"] = new[] { "Walkways clear", "Material storage", "Waste disposal", "Signage posted", "Fire extinguishers" }
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspection.SiteId = SiteId;
            _categories = DefaultChecklist.Keys.ToList();

            foreach (var (category, items) in DefaultChecklist)
            {
                foreach (var desc in items)
                {
                    _checklistItems.Add(new ChecklistItem
                    {
                        InspectionId = _inspection.Id,
                        Category = category,
                        Description = desc
                    });
                }
            }

            _initialized = true;
            StateHasChanged();
        }
    }

    private async Task SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = status;
        await Storage.SaveChecklistItemAsync(item);
    }

    private async Task Complete()
    {
        _inspection.CompletedAt = DateTimeOffset.Now;
        await Storage.SaveInspectionAsync(_inspection);

        foreach (var item in _checklistItems)
        {
            await Storage.SaveChecklistItemAsync(item);
        }

        Nav.NavigateTo("/");
    }

    private void GoBack() => Nav.NavigateTo("/");
}
