**SyncService.cs:**
```csharp
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncBatch
{
    public List<Inspection> Inspections { get; set; } = new();
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<Photo> Photos { get; set; } = new();
}

public class SyncService
{
    private readonly HttpClient _http;
    private readonly LocalStorageService _storage;
    private readonly ConnectivityService _connectivity;

    public event Action? OnSyncStatusChanged;

    public SyncService(HttpClient http, LocalStorageService storage, ConnectivityService connectivity)
    {
        _http = http;
        _storage = storage;
        _connectivity = connectivity;
    }

    public async Task<bool> TrySyncAsync()
    {
        if (!_connectivity.IsOnline) return false;

        try
        {
            var pendingInspections = await _storage.GetPendingInspectionsAsync();
            if (pendingInspections.Count == 0) return true;

            var batch = new SyncBatch { Inspections = pendingInspections };

            foreach (var inspection in pendingInspections)
            {
                var items = await _storage.GetChecklistItemsByInspectionAsync(inspection.Id);
                batch.ChecklistItems.AddRange(items);

                var photos = await _storage.GetPhotosByInspectionAsync(inspection.Id);
                batch.Photos.AddRange(photos);
            }

            var response = await _http.PostAsJsonAsync("/api/inspections/sync", batch);

            if (response.IsSuccessStatusCode)
            {
                foreach (var inspection in pendingInspections)
                {
                    inspection.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveInspectionAsync(inspection);
                }
                OnSyncStatusChanged?.Invoke();
                return true;
            }
            else
            {
                foreach (var inspection in pendingInspections)
                {
                    inspection.SyncStatus = SyncStatus.Failed;
                    await _storage.SaveInspectionAsync(inspection);
                }
                OnSyncStatusChanged?.Invoke();
                return false;
            }
        }
        catch
        {
            OnSyncStatusChanged?.Invoke();
            return false;
        }
    }
}
