**Create `SiteInspector.Client/Components/SyncStatusIndicator.razor`:**
```razor
@inject ConnectivityService Connectivity
@inject SyncService Sync
@inject LocalStorageService Storage
@implements IDisposable

<div class="sync-indicator">
    <span class="status-dot @(_isOnline ? "online" : "offline")"></span>
    <span class="status-text">@(_isOnline ? "Online" : "Offline")</span>
    @if (_pendingCount > 0)
    {
        <span class="pending-badge">@_pendingCount pending</span>
        @if (_isOnline)
        {
            <button class="btn-sync" @onclick="DoSync">Sync</button>
        }
    }
</div>

@code {
    private bool _isOnline;
    private int _pendingCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await Connectivity.InitializeAsync();
            _isOnline = Connectivity.IsOnline;
            Connectivity.OnConnectivityChanged += HandleConnectivityChanged;
            Sync.OnSyncStatusChanged += HandleSyncChanged;
            _pendingCount = await Storage.GetPendingSyncCountAsync();
            StateHasChanged();
        }
    }

    private async void HandleConnectivityChanged(bool isOnline)
    {
        _isOnline = isOnline;
        await InvokeAsync(StateHasChanged);
    }

    private async void HandleSyncChanged()
    {
        _pendingCount = await Storage.GetPendingSyncCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task DoSync()
    {
        await Sync.TrySyncAsync();
        _pendingCount = await Storage.GetPendingSyncCountAsync();
    }

    public void Dispose()
    {
        Connectivity.OnConnectivityChanged -= HandleConnectivityChanged;
        Sync.OnSyncStatusChanged -= HandleSyncChanged;
    }
}
```

