using SiteInspector.Client.Services;
using SiteInspector.Components;
using SiteInspector.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddSingleton<InMemoryDataStore>();

var app = builder.Build();

if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();

// API Endpoints
app.MapGet("/api/sites", (InMemoryDataStore store) => Results.Ok(store.GetSites()));

app.MapPost("/api/sites", (Site site, InMemoryDataStore store) =>
{
    store.AddSite(site);
    return Results.Created($"/api/sites/{site.Id}", site);
});

app.MapPost("/api/inspections/sync", (SyncBatch batch, InMemoryDataStore store) =>
{
    store.SyncBatch(batch.Inspections, batch.ChecklistItems, batch.Photos);
    return Results.Ok();
});

app.MapGet("/api/inspections/{siteId}", (string siteId, InMemoryDataStore store) =>
    Results.Ok(store.GetInspectionsBySite(siteId)));

