@inject SyncService Sync
@inject NavigationManager Nav

<div class="page-header">
    <h1>Site Inspector</h1>
    <SyncStatusIndicator />
</div>

<div class="card-list">
    @if (_sites.Count == 0)
    {
        <div class="empty-state">
            <p>No sites yet. Add your first construction site.</p>
        </div>
    }
    @foreach (var site in _sites)
    {
        <div class="card">
