                <h3>@site.Name</h3>
                <p class="card-address">@site.Address</p>
                <div class="card-actions">
                    <button class="btn btn-primary" @onclick="() => StartInspection(site.Id)">Start Inspection</button>
                    <button class="btn btn-secondary" @onclick="() => ViewHistory(site.Id)">History</button>
                </div>
            </div>
        </div>
    }
</div>

<div class="fab-container">
    <button class="fab" @onclick="AddSite">+ Add Site</button>
</div>

@code {
    private List<Site> _sites = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await Storage.InitializeAsync();
            _sites = await Storage.GetAllSitesAsync();
            StateHasChanged();
        }
    }

    private void StartInspection(string siteId) => Nav.NavigateTo($"/inspection/{siteId}");
    private void ViewHistory(string siteId) => Nav.NavigateTo($"/history/{siteId}");
    private void AddSite() => Nav.NavigateTo("/new-site");
}

