+@inject LocalStorageService Storage
+@inject IJSRuntime JS
+
+<div class="photo-capture">
+    <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment" class="photo-input" id="@_inputId" />
+    <label for="@_inputId" class="btn btn-secondary btn-sm">📷 Add Photo</label>
+
+    @if (_photos.Count > 0)
+    {
+        <div class="photo-thumbnails">
+            @foreach (var photo in _photos)
+            {
+                <div class="photo-thumb">
+                    <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
+                    <button class="photo-remove" @onclick="() => RemovePhoto(photo)">×</button>
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = string.Empty;
+    [Parameter] public string? ChecklistItemId { get; set; }
+
+    private List<Photo> _photos = new();
+    private string _inputId = $"photo-{Guid.NewGuid():N}";
+
+    private async Task HandleFileSelected(InputFileChangeEventArgs e)
+    {
+        var file = e.File;
+        if (file == null) return;
+
+        var resized = await file.RequestImageFileAsync("image/jpeg", 1024, 1024);
+        using var stream = resized.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
+        using var ms = new MemoryStream();
+        await stream.CopyToAsync(ms);
+        var base64 = Convert.ToBase64String(ms.ToArray());
+
+        var photo = new Photo
+        {
+            InspectionId = InspectionId,
+            ChecklistItemId = ChecklistItemId,
+            FileName = file.Name,
+            Base64Data = base64,
+            CapturedAt = DateTimeOffset.Now
+        };
+
+        await Storage.SavePhotoAsync(photo);
+        _photos.Add(photo);
+    }
+
+    private async Task RemovePhoto(Photo photo)
+    {
+        await Storage.DeletePhotoAsync(photo.Id);
+        _photos.Remove(photo);
+    }
+}
